using Portal.BuildingBlocks;using Portal.Menu.Application;using Portal.Menu.Contracts;
namespace Portal.Menu.Api;public static class MenuEndpoints{public static IEndpointRouteBuilder MapMenuEndpoints(this IEndpointRouteBuilder e){var g=e.MapGroup("/api/menu").RequireAuthorization();g.MapPost("/",async(CreateMenuRequest r,MenuService s,HttpContext h,CancellationToken c)=>Reply(h,await s.CreateMenuAsync(r,h.TraceIdentifier,c),201)).RequireAuthorization(PortalPermissions.MenuManage);g.MapPost("/items",async(CreateMenuItemRequest r,MenuService s,HttpContext h,CancellationToken c)=>Reply(h,await s.CreateItemAsync(r,h.TraceIdentifier,c),201)).RequireAuthorization(PortalPermissions.MenuManage);g.MapPut("/items/{id:guid}",async(Guid id,UpdateMenuItemRequest r,MenuService s,HttpContext h,CancellationToken c)=>Reply(h,await s.UpdateItemAsync(id,r,h.TraceIdentifier,c))).RequireAuthorization(PortalPermissions.MenuManage);g.MapPost("/items/{id:guid}/permissions",async(Guid id,AssignPermissionRequest r,MenuService s,HttpContext h,CancellationToken c)=>Reply(h,await s.AssignPermissionAsync(id,r,h.TraceIdentifier,c))).RequireAuthorization(PortalPermissions.MenuManage);g.MapGet("/user/{userId:guid}",async(Guid userId,string moduleCode,MenuService s,HttpContext h,CancellationToken c)=>Reply(h,await s.GetForUserAsync(userId,moduleCode,c))).RequireAuthorization(PortalPermissions.MenuRead);g.MapGet("/modules/{moduleCode}",async(string moduleCode,MenuService s,HttpContext h,CancellationToken c)=>Reply(h,await s.GetByModuleAsync(moduleCode,c))).RequireAuthorization(PortalPermissions.MenuRead);g.MapPost("/items/{id:guid}/activate",async(Guid id,MenuService s,HttpContext h,CancellationToken c)=>Reply(h,await s.SetActiveAsync(id,true,h.TraceIdentifier,c))).RequireAuthorization(PortalPermissions.MenuManage);g.MapPost("/items/{id:guid}/deactivate",async(Guid id,MenuService s,HttpContext h,CancellationToken c)=>Reply(h,await s.SetActiveAsync(id,false,h.TraceIdentifier,c))).RequireAuthorization(PortalPermissions.MenuManage);g.MapPost("/reorder",async(ReorderMenuRequest r,MenuService s,HttpContext h,CancellationToken c)=>Reply(h,await s.ReorderAsync(r,h.TraceIdentifier,c))).RequireAuthorization(PortalPermissions.MenuManage);return e;}static IResult Reply<T>(HttpContext h,Result<T> r,int status=200)=>r.IsSuccess?Results.Json(new ApiResponse<T>(r.Value,null,h.TraceIdentifier),statusCode:status):Results.Json(new ApiResponse<T>(default,r.Error,h.TraceIdentifier),statusCode:r.Error!.Code.EndsWith("not_found")?404:400);}
